using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary.
    /// Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalWordCount { get; set; }

    public int SummaryWordCount { get; set; }
}

namespace DocSummary.Services;

public interface ISummarizationService
{
    string Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization using word-frequency sentence scoring.
/// Splits the document into sentences, ranks each sentence by the
/// cumulative frequency of its non-stopword terms, and returns the
/// top-ranked sentences in their original document order.
/// </summary>
public partial class ExtractiveSummarizationService : ISummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","i","you","he","she","it",
        "we","they","me","him","her","us","them","my","your","his","its","our",
        "their","this","that","these","those","in","on","at","to","for","of",
        "with","by","from","as","into","about","between","through","during",
        "before","after","above","below","not","no","nor","so","if","then",
        "than","too","very","just","also","each","every","all","both","few",
        "more","most","other","some","such","only","own","same","when","where",
        "how","what","which","who","whom","why","while","up","down","out","off"
    };

    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);
        if (sentences.Count == 0)
            return string.Empty;

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((sentence, index) => (Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => sentences[s.Index]);

        return string.Join(" ", scored);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end-of-string.
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (!StopWords.Contains(word))
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = TokenizeWords(sentence);
        if (words.Count == 0)
            return 0;

        double score = 0;
        foreach (var word in words)
        {
            if (wordFrequencies.TryGetValue(word, out var freq))
                score += freq;
        }

        // Normalize by word count to avoid bias toward long sentences.
        return score / words.Count;
    }

    private static List<string> TokenizeWords(string text)
    {
        return WordRegex()
            .Matches(text)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly ISummarizationService _summarizationService;

    public SummarizeController(ISummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizationService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalWordCount = CountWords(request.DocumentText),
            SummaryWordCount = CountWords(summary)
        });
    }

    private static int CountWords(string text) =>
        string.IsNullOrWhiteSpace(text) ? 0 : text.Split((char[]?)null, StringSplitOptions.RemoveEmptyEntries).Length;
}

